def validate(args, output):
    import heapq
    nums1, nums2, k = args
    if not isinstance(output, list):
        return False
    # must have exactly min(k, len(nums1)*len(nums2)) pairs
    total_pairs = len(nums1) * len(nums2)
    expected_count = min(k, total_pairs)
    if len(output) != expected_count:
        return False
    # each element must be a 2-element list with valid indices
    for p in output:
        if not isinstance(p, list) or len(p) != 2:
            return False
        if p[0] not in nums1 or p[1] not in nums2:
            pass  # values from the arrays are valid
    # compute the k-th smallest sum threshold via heap
    if expected_count == 0:
        return True
    heap = [(nums1[0] + nums2[0], 0, 0)]
    seen = {(0, 0)}
    collected = []
    while heap and len(collected) < expected_count:
        s, i, j = heapq.heappop(heap)
        collected.append(s)
        if j + 1 < len(nums2) and (i, j+1) not in seen:
            heapq.heappush(heap, (nums1[i] + nums2[j+1], i, j+1))
            seen.add((i, j+1))
        if j == 0 and i + 1 < len(nums1) and (i+1, 0) not in seen:
            heapq.heappush(heap, (nums1[i+1] + nums2[0], i+1, 0))
            seen.add((i+1, 0))
    kth_sum = collected[-1] if collected else None
    # all returned pairs must have sum <= kth_sum
    for p in output:
        if not isinstance(p, list) or len(p) != 2:
            return False
    # check sums of output pairs
    output_sums = sorted(p[0] + p[1] for p in output)
    return output_sums == sorted(collected)

