function validate(args, output) {
    const [nums1, nums2, k] = args;
    if (!Array.isArray(output)) return false;
    const totalPairs = nums1.length * nums2.length;
    const expectedCount = Math.min(k, totalPairs);
    if (output.length !== expectedCount) return false;
    for (const p of output) {
        if (!Array.isArray(p) || p.length !== 2) return false;
    }
    // compute expected sums via min-heap
    const heap = [[nums1[0] + nums2[0], 0, 0]];
    const seen = new Set(['0,0']);
    const collected = [];
    function heappush(arr, item) {
        arr.push(item);
        let i = arr.length - 1;
        while (i > 0) {
            const parent = Math.floor((i - 1) / 2);
            if (arr[parent][0] <= arr[i][0]) break;
            [arr[parent], arr[i]] = [arr[i], arr[parent]];
            i = parent;
        }
    }
    function heappop(arr) {
        const top = arr[0];
        const last = arr.pop();
        if (arr.length > 0) {
            arr[0] = last;
            let i = 0;
            while (true) {
                let smallest = i;
                const l = 2*i+1, r = 2*i+2;
                if (l < arr.length && arr[l][0] < arr[smallest][0]) smallest = l;
                if (r < arr.length && arr[r][0] < arr[smallest][0]) smallest = r;
                if (smallest === i) break;
                [arr[i], arr[smallest]] = [arr[smallest], arr[i]];
                i = smallest;
            }
        }
        return top;
    }
    while (heap.length > 0 && collected.length < expectedCount) {
        const [s, i, j] = heappop(heap);
        collected.push(s);
        const k2 = j + 1;
        if (k2 < nums2.length && !seen.has(i+','+k2)) {
            heappush(heap, [nums1[i]+nums2[k2], i, k2]);
            seen.add(i+','+k2);
        }
        if (j === 0 && i+1 < nums1.length && !seen.has((i+1)+',0')) {
            heappush(heap, [nums1[i+1]+nums2[0], i+1, 0]);
            seen.add((i+1)+',0');
        }
    }
    const outputSums = output.map(p => p[0]+p[1]).sort((a,b)=>a-b);
    const collectedSorted = collected.sort((a,b)=>a-b);
    if (outputSums.length !== collectedSorted.length) return false;
    for (let i = 0; i < outputSums.length; i++) {
        if (outputSums[i] !== collectedSorted[i]) return false;
    }
    return true;
}

