class Solution:
    def kSmallestPairs(self, nums1, nums2, k):
        pairs = []
        for u in nums1:
            for v in nums2:
                pairs.append([u, v])
        pairs.sort(key=lambda p: p[0]+p[1])
        return pairs[:k]

